#include <bits/stdc++.h>
using namespace std;

class Solution {
    vector<vector<int>> graph;

    bool dfs(int vertex, vector<bool>& visited, int count, int N) {
        visited[vertex] = true;

        if(count == N) return true;

        for(int next : graph[vertex]) {
            if(!visited[next]) {
                if(dfs(next, visited, count+1, N)) 
                    return true;
                visited[next] = false;
            }
        }
        return false;
    }

public:
    bool hasHamiltonianPath(int N, int M, vector<vector<int>>& edges) {
        graph.resize(N+1);

        // Build adjacency list
        for(auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            graph[edge[1]].push_back(edge[0]);
        }

        vector<bool> visited(N+1, false);

        // Try starting from each vertex
        for(int i = 1; i <= N; i++) {
            fill(visited.begin(), visited.end(), false);
            if(dfs(i, visited, 1, N)) 
                return true;
        }
        return false;
    }
};

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n, m;
        cin >> n >> m;

        vector<vector<int>> edges(m, vector<int>(2));
        for(int i = 0; i < m; i++) {
            cin >> edges[i][0] >> edges[i][1];
        }

        Solution sol;
        cout << sol.hasHamiltonianPath(n, m, edges) << endl;
    }
    return 0;
}

