#include <stdio.h>
#include <stdbool.h>
#include <string.h>

int graph[11][11];
int N;

bool dfs(int vertex, bool visited[], int count) {
    visited[vertex] = true;

    if (count == N)
        return true;

    for (int next = 1; next <= N; next++) {
        if (graph[vertex][next] && !visited[next]) {
            if (dfs(next, visited, count + 1))
                return true;
            visited[next] = false;
        }
    }

    return false;
}

bool hasHamiltonianPath(int n, int m) {
    bool visited[11];
    for (int start = 1; start <= n; start++) {
        memset(visited, false, sizeof(visited));
        if (dfs(start, visited, 1))
            return true;
    }
    return false;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int m;
        scanf("%d %d", &N, &m);

        for (int i = 1; i <= N; i++)
            for (int j = 1; j <= N; j++)
                graph[i][j] = 0;

        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u][v] = 1;
            graph[v][u] = 1;
        }

        printf("%d\n", hasHamiltonianPath(N, m) ? 1 : 0);
    }

    return 0;
}
